create table aptitude_questions (correct_option varchar(1) not null, id bigint not null auto_increment, category varchar(255) not null, explanation TEXT, optiona varchar(255) not null, optionb varchar(255) not null, optionc varchar(255) not null, optiond varchar(255) not null, text TEXT not null, primary key (id)) engine=InnoDB;
create table aptitude_scores (score integer not null, total_questions integer not null, id bigint not null auto_increment, taken_at datetime(6) not null, category varchar(255) not null, username varchar(255) not null, primary key (id)) engine=InnoDB;
create table behavioral_questions (id bigint not null auto_increment, category varchar(255) not null, difficulty varchar(255), keywords varchar(255), question TEXT not null, star_sample TEXT, primary key (id)) engine=InnoDB;
create table resume_profiles (id bigint not null auto_increment, last_updated datetime(6), education TEXT, email varchar(255), experience TEXT, full_name varchar(255), github varchar(255), linkedin varchar(255), phone varchar(255), projects TEXT, skills TEXT, summary TEXT, username varchar(255) not null, primary key (id)) engine=InnoDB;
create table study_progress (completed bit not null, completed_at datetime(6), id bigint not null auto_increment, topic_id bigint not null, username varchar(255) not null, primary key (id)) engine=InnoDB;
create table study_topics (id bigint not null auto_increment, code_example TEXT, content TEXT, difficulty varchar(255), module varchar(255) not null, subject varchar(255) not null, tags varchar(255), title varchar(255) not null, primary key (id)) engine=InnoDB;
create table submissions (id bigint not null auto_increment, code TEXT, language varchar(255), output TEXT, question_name varchar(255), status varchar(255), user_email varchar(255), primary key (id)) engine=InnoDB;
create table user_activity (best_streak integer, easy_solved integer, hard_solved integer, medium_solved integer, quizzes_taken integer, streak_days integer, submissions integer, total_points integer, total_solved integer not null, id bigint not null auto_increment, last_active datetime(6), username varchar(255) not null, primary key (id)) engine=InnoDB;
create table users (id bigint not null auto_increment, email varchar(255), name varchar(255) not null, password varchar(255), primary key (id)) engine=InnoDB;
alter table resume_profiles add constraint UK_skpvrbkef80kirxqqmq1fn3g9 unique (username);
alter table user_activity add constraint UK_aj1tc6ykwnallbsl803le3kp2 unique (username);
alter table users add constraint UK_6dotkott2kjsp8vw4d0m25fb7 unique (email);
